if (! function_exists('filesystem_analyzer')) {
    function filesystem_analyzer($path = null, $max_depth = null, $max_files = null, $min_size = null, $extensions = null, $show_hidden = null, $timeout = null)
    {
        // Filesystem Analyzer - recursive directory scanning and statistics
        // Helper closure defined FIRST
        $fmtBytes = function($bytes) {
            if ($bytes >= 1073741824) return round($bytes / 1073741824, 2) . ' GB';
            if ($bytes >= 1048576) return round($bytes / 1048576, 2) . ' MB';
            if ($bytes >= 1024) return round($bytes / 1024, 1) . ' KB';
            return $bytes . ' B';
        };

        $input_path = isset($path) ? (string)$path : 'storage/agent/workspace';
        $max_depth = isset($max_depth) ? max(0, (int)$max_depth) : 10;
        $max_files = isset($max_files) ? max(0, (int)$max_files) : 10000;
        $min_size = isset($min_size) ? max(0, (int)$min_size) : 0;
        $ext_filter = isset($extensions) ? (string)$extensions : '';
        $show_hidden = isset($show_hidden) ? (bool)$show_hidden : false;
        $timeout = isset($timeout) ? min(max((int)$timeout, 5), 60) : 30;

        // Resolve path
        $base = realpath($input_path);
        if ($base === false) {
            $project_root = realpath(__DIR__ . '/../../../..');
            $base = realpath($project_root . '/' . ltrim($input_path, '/'));
        }
        if ($base === false || !is_dir($base)) {
            return ['error' => "Directory not found: {$input_path}", 'scan_path' => $input_path];
        }

        // Parse extension filter
        $ext_map = [];
        if ($ext_filter !== '') {
            foreach (explode(',', $ext_filter) as $e) {
                $e = trim(strtolower(ltrim($e, '.')));
                if ($e !== '') $ext_map[$e] = true;
            }
        }

        $start_time = microtime(true);
        $deadline = $start_time + $timeout;

        $results = [
            'success' => true,
            'scan_path' => $base,
            'scan_path_relative' => $input_path,
        ];

        try {
            $files = [];
            $dirs = [];
            $total_size = 0;
            $total_files = 0;
            $total_dirs = 0;
            $skipped_hidden = 0;
            $skipped_size = 0;
            $skipped_ext = 0;
            $errored = 0;
            $largest_files = [];
            $newest_files = [];
            $oldest_files = [];
            
            $flags = RecursiveDirectoryIterator::SKIP_DOTS;
            $iterator = new RecursiveDirectoryIterator($base, $flags);
            $recursive = new RecursiveIteratorIterator(
                $iterator,
                RecursiveIteratorIterator::SELF_FIRST,
                RecursiveIteratorIterator::CATCH_GET_CHILD
            );
            
            if ($max_depth > 0) {
                $recursive->setMaxDepth($max_depth);
            }
            
            $processed = 0;
            
            foreach ($recursive as $item) {
                if (microtime(true) > $deadline) {
                    $results['timeout'] = true;
                    break;
                }
                if ($max_files > 0 && $processed >= $max_files) {
                    $results['max_files_reached'] = true;
                    break;
                }
                
                try {
                    $basename = $item->getBasename();
                    
                    if (!$show_hidden && $basename !== '' && $basename[0] === '.') {
                        $skipped_hidden++;
                        continue;
                    }
                    
                    if ($item->isDir()) {
                        $total_dirs++;
                        $processed++;
                        continue;
                    }
                    
                    if (!$item->isFile()) continue;
                    
                    $size = $item->getSize();
                    $ext = strtolower($item->getExtension());
                    $mtime = $item->getMTime();
                    
                    if ($size < $min_size) { $skipped_size++; continue; }
                    if (!empty($ext_map) && !isset($ext_map[$ext])) { $skipped_ext++; continue; }
                    
                    $total_files++;
                    $total_size += $size;
                    $processed++;
                    
                    $realpath = $item->getRealPath();
                    $info = [
                        'path' => $realpath ?: $item->getPathname(),
                        'name' => $basename,
                        'ext' => $ext,
                        'size' => $size,
                        'size_human' => $fmtBytes($size),
                        'modified' => $mtime,
                        'modified_date' => date('Y-m-d H:i:s', $mtime),
                    ];
                    
                    $files[] = $info;
                    
                    // Track largest files (top 20)
                    $largest_files[] = $info;
                    usort($largest_files, fn($a, $b) => $b['size'] - $a['size']);
                    if (count($largest_files) > 20) array_pop($largest_files);
                    
                    // Track newest files (top 10)
                    $newest_files[] = $info;
                    usort($newest_files, fn($a, $b) => $b['modified'] - $a['modified']);
                    if (count($newest_files) > 10) array_pop($newest_files);
                    
                    // Track oldest files (top 10)
                    $oldest_files[] = $info;
                    usort($oldest_files, fn($a, $b) => $a['modified'] - $b['modified']);
                    if (count($oldest_files) > 10) array_pop($oldest_files);
                    
                } catch (\Throwable $e) {
                    $errored++;
                }
            }
            
            // Build extension statistics
            $ext_stats = [];
            foreach ($files as $f) {
                $e = $f['ext'] ?: '(no extension)';
                if (!isset($ext_stats[$e])) {
                    $ext_stats[$e] = ['count' => 0, 'total_size' => 0, 'min_size' => PHP_INT_MAX, 'max_size' => 0];
                }
                $ext_stats[$e]['count']++;
                $ext_stats[$e]['total_size'] += $f['size'];
                $ext_stats[$e]['min_size'] = min($ext_stats[$e]['min_size'], $f['size']);
                $ext_stats[$e]['max_size'] = max($ext_stats[$e]['max_size'], $f['size']);
            }
            uasort($ext_stats, fn($a, $b) => $b['total_size'] - $a['total_size']);
            
            // Size distribution
            $size_brackets = ['0-1KB' => 0, '1-10KB' => 0, '10-100KB' => 0, '100KB-1MB' => 0, '1-10MB' => 0, '10-100MB' => 0, '>100MB' => 0];
            foreach ($files as $f) {
                $s = $f['size'];
                if ($s < 1024) $size_brackets['0-1KB']++;
                elseif ($s < 10240) $size_brackets['1-10KB']++;
                elseif ($s < 102400) $size_brackets['10-100KB']++;
                elseif ($s < 1048576) $size_brackets['100KB-1MB']++;
                elseif ($s < 10485760) $size_brackets['1-10MB']++;
                elseif ($s < 104857600) $size_brackets['10-100MB']++;
                else $size_brackets['>100MB']++;
            }
            
            // Age distribution
            $now = time();
            $day = 86400;
            $age_brackets = ['today (0-1d)' => 0, 'week (1-7d)' => 0, 'month (7-30d)' => 0, 'quarter (30-90d)' => 0, 'year (90-365d)' => 0, 'older (>1y)' => 0];
            foreach ($files as $f) {
                $age = $now - $f['modified'];
                if ($age < $day) $age_brackets['today (0-1d)']++;
                elseif ($age < 7*$day) $age_brackets['week (1-7d)']++;
                elseif ($age < 30*$day) $age_brackets['month (7-30d)']++;
                elseif ($age < 90*$day) $age_brackets['quarter (30-90d)']++;
                elseif ($age < 365*$day) $age_brackets['year (90-365d)']++;
                else $age_brackets['older (>1y)']++;
            }
            
            // Duplicate filenames
            $name_map = [];
            foreach ($files as $f) { $name_map[$f['name']][] = $f['path']; }
            $duplicates = [];
            foreach ($name_map as $name => $paths) {
                if (count($paths) > 1) $duplicates[] = ['name' => $name, 'count' => count($paths), 'paths' => $paths];
            }
            usort($duplicates, fn($a, $b) => $b['count'] - $a['count']);
            
            $elapsed = round((microtime(true) - $start_time) * 1000, 1);
            
            // Format extension summary
            $ext_summary = [];
            foreach ($ext_stats as $ext => $stats) {
                $ext_summary[] = [
                    'extension' => $ext,
                    'count' => $stats['count'],
                    'total_size' => $stats['total_size'],
                    'total_size_human' => $fmtBytes($stats['total_size']),
                    'avg_size' => (int)($stats['total_size'] / max($stats['count'], 1)),
                    'max_size' => $stats['max_size'],
                ];
            }
            
            return [
                'success' => true,
                'scan_path' => $input_path,
                'elapsed_ms' => $elapsed,
                'summary' => [
                    'total_directories' => $total_dirs,
                    'total_files' => $total_files,
                    'total_size' => $total_size,
                    'total_size_human' => $fmtBytes($total_size),
                    'avg_file_size' => $total_files > 0 ? $fmtBytes((int)($total_size / $total_files)) : '0 B',
                ],
                'skipped' => [
                    'hidden' => $skipped_hidden,
                    'by_size' => $skipped_size,
                    'by_extension' => $skipped_ext,
                    'errors' => $errored,
                ],
                'extensions' => $ext_summary,
                'size_distribution' => $size_brackets,
                'age_distribution' => $age_brackets,
                'largest_files' => $largest_files,
                'newest_files' => $newest_files,
                'oldest_files' => $oldest_files,
                'duplicate_names' => count($duplicates),
                'duplicates' => array_slice($duplicates, 0, 10),
            ];
            
        } catch (\Throwable $e) {
            return [
                'error' => 'Filesystem analysis failed: ' . $e->getMessage(),
                'scan_path' => $input_path,
            ];
        }
    }
}
